import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

console.log('đź”Ť API URL:', API_URL);

const api = axios.create({
    baseURL: API_URL,
    headers: {
        'Content-Type': 'application/json'
    },
    timeout: 15000
});

// âś… Request interceptor - adds token to EVERY request
api.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
            console.log('đź”‘ Token added to request:', config.url);
        } else {
            console.log('âš ď¸Ź No token found for request:', config.url);
        }
        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

// âś… Response interceptor - handles errors
api.interceptors.response.use(
    (response) => {
        console.log('đź“Ą Response:', response.status, response.config.url);
        return response;
    },
    (error) => {
        console.error('âťŚ API Error:', error.response?.status, error.response?.data);

        if (error.response?.status === 401) {
            console.log('đź”’ 401 Unauthorized - Clearing session');
            localStorage.removeItem('token');
            localStorage.removeItem('user');
            window.location.href = '/login';
        }
        return Promise.reject(error);
    }
);

export default api;
